/**
 * QR Code Generator
 * A minimal but fully functional QR code generator supporting error correction level M.
 * Based on the QR code specification (ISO 18004).
 *
 * Usage:
 *   var qr = new QRCode(0, QRCode.ErrorCorrectLevel.M);
 *   qr.addData("hello");
 *   qr.make();
 *   var count = qr.getModuleCount();
 *   var isDark = qr.isDark(row, col);
 */

var QRCode = (function () {
  "use strict";

  // ========================================================================
  // Constants
  // ========================================================================

  var PAD0 = 0xEC;
  var PAD1 = 0x11;

  var ErrorCorrectLevel = {
    L: 1,
    M: 0,
    Q: 3,
    H: 2,
  };

  // Number of error correction codewords per block for each version & EC level
  // Index: [version-1][ecLevel]
  // Format: [totalDataCodewords, ecCodewordsPerBlock, numBlocks, ...groups]
  var RS_BLOCK_TABLE = [
    // Version 1
    [1,26,19,1, 1,26,16,1, 1,26,13,1, 1,26,9,1],
    // Version 2
    [1,44,34,1, 1,44,28,1, 1,44,22,1, 1,44,16,1],
    // Version 3
    [1,70,55,1, 1,70,44,1, 2,35,17,1, 2,35,13,1],
    // Version 4
    [1,100,80,1, 2,50,32,1, 2,50,24,1, 4,25,9,1],
    // Version 5
    [1,134,108,1, 2,67,43,1, 2,33,15,2, 2,33,11,2],
    // Version 6
    [2,86,68,1, 4,43,27,1, 4,43,19,1, 4,43,15,1],
    // Version 7
    [2,98,78,1, 4,49,31,1, 2,32,14,4, 4,39,13,1],
    // Version 8
    [2,121,97,1, 2,60,38,2, 4,40,18,2, 4,40,14,2],
    // Version 9
    [2,146,116,1, 3,58,36,2, 4,36,16,4, 4,36,12,4],
    // Version 10
    [2,86,68,2, 4,69,43,1, 6,43,19,2, 6,43,15,2],
  ];

  // More accurate RS block data for versions 1-10 at EC level M
  var EC_PARAMS = {
    // version: [numBlocks, ecPerBlock, dataPerBlock]
    1:  [[1, 10, 16]],
    2:  [[1, 16, 28]],
    3:  [[1, 26, 44]],
    4:  [[2, 18, 32]],
    5:  [[2, 24, 43]],
    6:  [[4, 16, 27]],
    7:  [[4, 18, 31]],
    8:  [[2, 22, 38], [2, 22, 36]],
    9:  [[3, 22, 36], [2, 22, 36]],
    10: [[4, 26, 43], [1, 26, 43]],
  };

  // Total codewords per version
  var TOTAL_CODEWORDS = [0, 26, 44, 70, 100, 134, 172, 196, 242, 292, 346];

  // Data capacity at EC level M (byte mode) per version
    var DATA_CAPACITY_M = [0, 16, 28, 44, 64, 86, 108, 124, 148, 180, 215];
  // Alignment pattern positions per version
  var ALIGNMENT_POSITIONS = [
    [],       // v1
    [6, 18],  // v2
    [6, 22],  // v3
    [6, 26],  // v4
    [6, 30],  // v5
    [6, 34],  // v6
    [6, 22, 38], // v7
    [6, 24, 42], // v8
    [6, 26, 46], // v9
    [6, 28, 50], // v10
  ];

  // ========================================================================
  // GF(256) math for Reed-Solomon error correction
  // ========================================================================

  var EXP_TABLE = new Array(256);
  var LOG_TABLE = new Array(256);

  (function () {
    var x = 1;
    for (var i = 0; i < 255; i++) {
      EXP_TABLE[i] = x;
      LOG_TABLE[x] = i;
      x <<= 1;
      if (x >= 256) x ^= 0x11D; // primitive polynomial for GF(256)
    }
    EXP_TABLE[255] = EXP_TABLE[0];
  })();

  function gfMul(a, b) {
    if (a === 0 || b === 0) return 0;
    return EXP_TABLE[(LOG_TABLE[a] + LOG_TABLE[b]) % 255];
  }

  /**
   * Generate Reed-Solomon error correction codewords.
   */
  function rsEncode(data, ecCount) {
    // Build generator polynomial
    var gen = [1];
    for (var i = 0; i < ecCount; i++) {
      var newGen = new Array(gen.length + 1).fill(0);
      for (var j = 0; j < gen.length; j++) {
        newGen[j] ^= gen[j];
        newGen[j + 1] ^= gfMul(gen[j], EXP_TABLE[i]);
      }
      gen = newGen;
    }

    // Polynomial division
    var remainder = new Array(ecCount).fill(0);
    for (var i = 0; i < data.length; i++) {
      var factor = data[i] ^ remainder[0];
      remainder.shift();
      remainder.push(0);
      for (var j = 0; j < ecCount; j++) {
        remainder[j] ^= gfMul(factor, gen[j + 1]);
      }
    }
    return remainder;
  }

  // ========================================================================
  // Bit Buffer
  // ========================================================================

  function BitBuffer() {
    this.buffer = [];
    this.length = 0;
  }

  BitBuffer.prototype.put = function (num, length) {
    for (var i = 0; i < length; i++) {
      this.putBit(((num >>> (length - i - 1)) & 1) === 1);
    }
  };

  BitBuffer.prototype.putBit = function (bit) {
    var bufIndex = Math.floor(this.length / 8);
    if (this.buffer.length <= bufIndex) {
      this.buffer.push(0);
    }
    if (bit) {
      this.buffer[bufIndex] |= 0x80 >>> (this.length % 8);
    }
    this.length++;
  };

  BitBuffer.prototype.getBuffer = function () {
    return this.buffer;
  };

  BitBuffer.prototype.getLengthInBits = function () {
    return this.length;
  };

  // ========================================================================
  // QRCode
  // ========================================================================

  function QRCodeModel(typeNumber, errorCorrectLevel) {
    this.typeNumber = typeNumber;
    // This generator implementation is tuned for EC level M tables/capacity.
    if (errorCorrectLevel !== ErrorCorrectLevel.M && typeof console !== "undefined" && console.warn) {
      console.warn("QRCodeModel supports only EC level M. Forcing M.");
    }
    this.errorCorrectLevel = ErrorCorrectLevel.M;
    this.modules = null;
    this.moduleCount = 0;
    this.dataCache = null;
    this.dataList = [];
  }

  QRCodeModel.prototype.addData = function (data) {
    this.dataList.push(data);
    this.dataCache = null;
  };

  QRCodeModel.prototype.make = function () {
    if (this.typeNumber < 1) {
      this.typeNumber = this._detectVersion();
    }
    this.moduleCount = this.typeNumber * 4 + 17;
    this.modules = new Array(this.moduleCount);
    for (var row = 0; row < this.moduleCount; row++) {
      this.modules[row] = new Array(this.moduleCount);
      for (var col = 0; col < this.moduleCount; col++) {
        this.modules[row][col] = null;
      }
    }

    this._setupPositionProbePattern(0, 0);
    this._setupPositionProbePattern(this.moduleCount - 7, 0);
    this._setupPositionProbePattern(0, this.moduleCount - 7);
    this._setupAlignmentPattern();
    this._setupTimingPattern();

    this._setupFormatInfo(false, 0);
    if (this.typeNumber >= 7) {
      this._setupVersionInfo(false);
    }

    if (this.dataCache === null) {
      this.dataCache = this._createData();
    }

    this._mapData(this.dataCache, 0);

    // Find best mask
    var minPenalty = Infinity;
    var bestMask = 0;

    for (var mask = 0; mask < 8; mask++) {
      // Reset modules
      this.modules = new Array(this.moduleCount);
      for (var row = 0; row < this.moduleCount; row++) {
        this.modules[row] = new Array(this.moduleCount);
        for (var col = 0; col < this.moduleCount; col++) {
          this.modules[row][col] = null;
        }
      }

      this._setupPositionProbePattern(0, 0);
      this._setupPositionProbePattern(this.moduleCount - 7, 0);
      this._setupPositionProbePattern(0, this.moduleCount - 7);
      this._setupAlignmentPattern();
      this._setupTimingPattern();
      this._setupFormatInfo(false, mask);
      if (this.typeNumber >= 7) {
        this._setupVersionInfo(false);
      }
      this._mapData(this.dataCache, mask);

      var penalty = this._calculatePenalty();
      if (penalty < minPenalty) {
        minPenalty = penalty;
        bestMask = mask;
      }
    }

    // Apply best mask
    this.modules = new Array(this.moduleCount);
    for (var row = 0; row < this.moduleCount; row++) {
      this.modules[row] = new Array(this.moduleCount);
      for (var col = 0; col < this.moduleCount; col++) {
        this.modules[row][col] = null;
      }
    }

    this._setupPositionProbePattern(0, 0);
    this._setupPositionProbePattern(this.moduleCount - 7, 0);
    this._setupPositionProbePattern(0, this.moduleCount - 7);
    this._setupAlignmentPattern();
    this._setupTimingPattern();
    this._setupFormatInfo(false, bestMask);
    if (this.typeNumber >= 7) {
      this._setupVersionInfo(false);
    }
    this._mapData(this.dataCache, bestMask);
  };

  QRCodeModel.prototype.getModuleCount = function () {
    return this.moduleCount;
  };

  QRCodeModel.prototype.isDark = function (row, col) {
    if (row < 0 || this.moduleCount <= row || col < 0 || this.moduleCount <= col) {
      return false;
    }
    return this.modules[row][col] === true;
  };

    QRCodeModel.prototype._detectVersion = function () {
        var dataStr = this.dataList.join("");
        var dataLen = this._utf8Length(dataStr);

        for (var v = 1; v <= 10; v++) {
            // Header size: Mode indicator (4 bits) + Character count length
            var ccBits = v <= 9 ? 8 : 16;
            var totalBits = 4 + ccBits + (dataLen * 8);

            // Check if total bits fit within the allowed data codewords
            if (totalBits <= DATA_CAPACITY_M[v] * 8) {
                return v;
            }
        }
        throw new Error("Data too long for QR code (max version 10 supported)");
    };

  QRCodeModel.prototype._utf8Length = function (str) {
    var len = 0;
    for (var i = 0; i < str.length; i++) {
      var c = str.charCodeAt(i);
      if (c < 0x80) len += 1;
      else if (c < 0x800) len += 2;
      else if (c < 0x10000) len += 3;
      else len += 4;
    }
    return len;
  };

  QRCodeModel.prototype._utf8Encode = function (str) {
    var bytes = [];
    for (var i = 0; i < str.length; i++) {
      var c = str.charCodeAt(i);
      if (c < 0x80) {
        bytes.push(c);
      } else if (c < 0x800) {
        bytes.push(0xC0 | (c >> 6));
        bytes.push(0x80 | (c & 0x3F));
      } else if (c < 0x10000) {
        bytes.push(0xE0 | (c >> 12));
        bytes.push(0x80 | ((c >> 6) & 0x3F));
        bytes.push(0x80 | (c & 0x3F));
      } else {
        bytes.push(0xF0 | (c >> 18));
        bytes.push(0x80 | ((c >> 12) & 0x3F));
        bytes.push(0x80 | ((c >> 6) & 0x3F));
        bytes.push(0x80 | (c & 0x3F));
      }
    }
    return bytes;
  };

  QRCodeModel.prototype._setupPositionProbePattern = function (row, col) {
    for (var r = -1; r <= 7; r++) {
      if (row + r <= -1 || this.moduleCount <= row + r) continue;
      for (var c = -1; c <= 7; c++) {
        if (col + c <= -1 || this.moduleCount <= col + c) continue;
        if (
          (0 <= r && r <= 6 && (c === 0 || c === 6)) ||
          (0 <= c && c <= 6 && (r === 0 || r === 6)) ||
          (2 <= r && r <= 4 && 2 <= c && c <= 4)
        ) {
          this.modules[row + r][col + c] = true;
        } else {
          this.modules[row + r][col + c] = false;
        }
      }
    }
  };

  QRCodeModel.prototype._setupAlignmentPattern = function () {
    var pos = ALIGNMENT_POSITIONS[this.typeNumber - 1];
    if (!pos || pos.length === 0) return;

    for (var i = 0; i < pos.length; i++) {
      for (var j = 0; j < pos.length; j++) {
        var row = pos[i];
        var col = pos[j];

        if (this.modules[row][col] !== null) continue;

        for (var r = -2; r <= 2; r++) {
          for (var c = -2; c <= 2; c++) {
            if (
              r === -2 || r === 2 || c === -2 || c === 2 ||
              (r === 0 && c === 0)
            ) {
              this.modules[row + r][col + c] = true;
            } else {
              this.modules[row + r][col + c] = false;
            }
          }
        }
      }
    }
  };

  QRCodeModel.prototype._setupTimingPattern = function () {
    for (var r = 8; r < this.moduleCount - 8; r++) {
      if (this.modules[r][6] !== null) continue;
      this.modules[r][6] = (r % 2 === 0);
    }
    for (var c = 8; c < this.moduleCount - 8; c++) {
      if (this.modules[6][c] !== null) continue;
      this.modules[6][c] = (c % 2 === 0);
    }
  };

    QRCodeModel.prototype._setupFormatInfo = function (test, maskPattern) {
        var data = (this.errorCorrectLevel << 3) | maskPattern;
        var bits = data;

        // BCH(15,5) encoding
        for (var i = 0; i < 10; i++) {
            bits <<= 1;
        }
        var remainder = bits;
        var gen = 0x537; // generator polynomial
        while (getBCHDigit(remainder) >= getBCHDigit(gen)) {
            remainder ^= gen << (getBCHDigit(remainder) - getBCHDigit(gen));
        }
        var formatInfo = ((data << 10) | remainder) ^ 0x5412; // XOR with mask pattern

        // Place format information
        for (var i = 0; i < 15; i++) {
            var mod = !test && ((formatInfo >> i) & 1) === 1;

            // --- Copy 1: Wrapped around the Top-Left finder pattern ---
            var r1, c1;
            if (i < 6) {
                r1 = 8; c1 = i;
            } else if (i < 8) {
                r1 = 8; c1 = i + 1; // Skips the timing pattern at col 6
            } else if (i === 8) {
                r1 = 7; c1 = 8;
            } else {
                r1 = 14 - i; c1 = 8;
            }
            this.modules[r1][c1] = mod;

            // --- Copy 2: Split between Bottom-Left and Top-Right finder patterns ---
            var r2, c2;
            if (i < 7) {
                r2 = this.moduleCount - 1 - i; c2 = 8;
            } else {
                r2 = 8; c2 = this.moduleCount - 8 + (i - 7);
            }
            this.modules[r2][c2] = mod;
        }

        // Fixed dark module (Mandatory QR specification)
        this.modules[this.moduleCount - 8][8] = !test;
    };

  QRCodeModel.prototype._setupVersionInfo = function (test) {
    // Version info is only for version >= 7
    if (this.typeNumber < 7) return;

    var bits = this.typeNumber;
    for (var i = 0; i < 12; i++) {
      bits <<= 1;
    }
    var remainder = bits;
    var gen = 0x1F25;
    while (getBCHDigit(remainder) >= getBCHDigit(gen)) {
      remainder ^= gen << (getBCHDigit(remainder) - getBCHDigit(gen));
    }
    var versionInfo = (this.typeNumber << 12) | remainder;

    for (var i = 0; i < 18; i++) {
      var mod = !test && ((versionInfo >> i) & 1) === 1;
      this.modules[Math.floor(i / 3)][this.moduleCount - 11 + (i % 3)] = mod;
      this.modules[this.moduleCount - 11 + (i % 3)][Math.floor(i / 3)] = mod;
    }
  };

  QRCodeModel.prototype._createData = function () {
    var version = this.typeNumber;
    var buffer = new BitBuffer();
    var dataStr = this.dataList.join("");
    var dataBytes = this._utf8Encode(dataStr);

    // Mode indicator: byte mode = 0100
    buffer.put(4, 4);

    // Character count indicator (byte mode)
    var ccBits = version <= 9 ? 8 : 16;
    buffer.put(dataBytes.length, ccBits);

    // Data
    for (var i = 0; i < dataBytes.length; i++) {
      buffer.put(dataBytes[i], 8);
    }

    // Terminator
    var totalDataBits = DATA_CAPACITY_M[version] * 8;
    if (buffer.getLengthInBits() + 4 <= totalDataBits) {
      buffer.put(0, 4);
    }

    // Byte alignment
    while (buffer.getLengthInBits() % 8 !== 0) {
      buffer.putBit(false);
    }

    // Padding bytes
    var totalDataCodewords = DATA_CAPACITY_M[version];
    while (buffer.getBuffer().length < totalDataCodewords) {
      buffer.put(PAD0, 8);
      if (buffer.getBuffer().length >= totalDataCodewords) break;
      buffer.put(PAD1, 8);
    }

    return this._interleaveData(buffer.getBuffer());
  };

  QRCodeModel.prototype._interleaveData = function (data) {
    var version = this.typeNumber;
    var params = EC_PARAMS[version];
    if (!params) {
      throw new Error("Unsupported QR version: " + version);
    }

    var blocks = [];
    var ecBlocks = [];
    var dataOffset = 0;

    for (var g = 0; g < params.length; g++) {
      var numBlocks = params[g][0];
      var ecPerBlock = params[g][1];
      var dataPerBlock = params[g][2];

      for (var b = 0; b < numBlocks; b++) {
        var blockData = data.slice(dataOffset, dataOffset + dataPerBlock);
        dataOffset += dataPerBlock;
        blocks.push(blockData);
        ecBlocks.push(rsEncode(blockData, ecPerBlock));
      }
    }

    // Interleave data codewords
    var result = [];
    var maxDataLen = Math.max.apply(null, blocks.map(function(b) { return b.length; }));
    for (var i = 0; i < maxDataLen; i++) {
      for (var j = 0; j < blocks.length; j++) {
        if (i < blocks[j].length) {
          result.push(blocks[j][i]);
        }
      }
    }

    // Interleave EC codewords
    var maxEcLen = Math.max.apply(null, ecBlocks.map(function(b) { return b.length; }));
    for (var i = 0; i < maxEcLen; i++) {
      for (var j = 0; j < ecBlocks.length; j++) {
        if (i < ecBlocks[j].length) {
          result.push(ecBlocks[j][i]);
        }
      }
    }

    return result;
  };

  QRCodeModel.prototype._mapData = function (data, maskPattern) {
    var inc = -1;
    var row = this.moduleCount - 1;
    var bitIndex = 7;
    var byteIndex = 0;

    for (var col = this.moduleCount - 1; col > 0; col -= 2) {
      if (col === 6) col--; // Skip timing pattern column

      while (true) {
        for (var c = 0; c < 2; c++) {
          if (this.modules[row][col - c] === null) {
            var dark = false;

            if (byteIndex < data.length) {
              dark = ((data[byteIndex] >>> bitIndex) & 1) === 1;
            }

            if (getMaskFunction(maskPattern)(row, col - c)) {
              dark = !dark;
            }

            this.modules[row][col - c] = dark;
            bitIndex--;

            if (bitIndex < 0) {
              byteIndex++;
              bitIndex = 7;
            }
          }
        }

        row += inc;

        if (row < 0 || this.moduleCount <= row) {
          row -= inc;
          inc = -inc;
          break;
        }
      }
    }
  };

  QRCodeModel.prototype._calculatePenalty = function () {
    var penalty = 0;
    var moduleCount = this.moduleCount;

    // Rule 1: Adjacent modules in row/column in same color
    for (var row = 0; row < moduleCount; row++) {
      var count = 1;
      for (var col = 1; col < moduleCount; col++) {
        if (this.modules[row][col] === this.modules[row][col - 1]) {
          count++;
          if (count === 5) penalty += 3;
          else if (count > 5) penalty += 1;
        } else {
          count = 1;
        }
      }
    }

    for (var col = 0; col < moduleCount; col++) {
      var count = 1;
      for (var row = 1; row < moduleCount; row++) {
        if (this.modules[row][col] === this.modules[row - 1][col]) {
          count++;
          if (count === 5) penalty += 3;
          else if (count > 5) penalty += 1;
        } else {
          count = 1;
        }
      }
    }

    // Rule 2: 2x2 blocks of same color
    for (var row = 0; row < moduleCount - 1; row++) {
      for (var col = 0; col < moduleCount - 1; col++) {
        var val = this.modules[row][col];
        if (
          val === this.modules[row][col + 1] &&
          val === this.modules[row + 1][col] &&
          val === this.modules[row + 1][col + 1]
        ) {
          penalty += 3;
        }
      }
    }

    // Rule 3: Finder-like patterns (simplified)
    // Rule 4: Proportion of dark modules
    var darkCount = 0;
    for (var row = 0; row < moduleCount; row++) {
      for (var col = 0; col < moduleCount; col++) {
        if (this.modules[row][col]) darkCount++;
      }
    }
    var ratio = Math.abs(100 * darkCount / (moduleCount * moduleCount) - 50) / 5;
    penalty += ratio * 10;

    return penalty;
  };

  // ========================================================================
  // Mask functions
  // ========================================================================

  function getMaskFunction(maskPattern) {
    switch (maskPattern) {
      case 0: return function (i, j) { return (i + j) % 2 === 0; };
      case 1: return function (i, j) { return i % 2 === 0; };
      case 2: return function (i, j) { return j % 3 === 0; };
      case 3: return function (i, j) { return (i + j) % 3 === 0; };
      case 4: return function (i, j) { return (Math.floor(i / 2) + Math.floor(j / 3)) % 2 === 0; };
      case 5: return function (i, j) { return ((i * j) % 2) + ((i * j) % 3) === 0; };
      case 6: return function (i, j) { return (((i * j) % 2) + ((i * j) % 3)) % 2 === 0; };
      case 7: return function (i, j) { return (((i * j) % 3) + ((i + j) % 2)) % 2 === 0; };
      default: throw new Error("Invalid mask pattern: " + maskPattern);
    }
  }

  // ========================================================================
  // Utility
  // ========================================================================

  function getBCHDigit(data) {
    var digit = 0;
    while (data !== 0) {
      digit++;
      data >>>= 1;
    }
    return digit;
  }

  // ========================================================================
  // Public API
  // ========================================================================

  QRCodeModel.ErrorCorrectLevel = ErrorCorrectLevel;

  return QRCodeModel;
})();
